buttonColor:
{{ 
  (() => {
    // 1. Sicheres Array holen (fängt ab, wenn Daten noch laden)
    const daten = Bewaesserung_Lesen.data || [];

    // 2. Aktuelle Ventilnummer aus der Liste/Tabelle holen
    const aktivesVentil = String(currentItem.Ventil || currentItem.Ventil_Links || currentItem.Ventil_Rechts || "").trim();

    if (!aktivesVentil) return "#E0E0E0"; // Grau, falls kein Ventil da ist

    // 3. Eintrag suchen (schaut nach 'Ventil' oder 'ventilName')
    const e = daten.find(row => {
      const vVal = String(row.Ventil || row.ventilName || "").trim();
      return vVal === aktivesVentil || parseFloat(vVal) === parseFloat(aktivesVentil);
    });

    // 4. Wenn kein Eintrag existiert oder kein Programm gesetzt ist -> Grau
    if (!e || !e.Programm) return "#E0E0E0"; 

    // 5. Farbe nach Programm zuweisen
    switch (String(e.Programm).trim()) {
      case "Viel": 
        return "#1d4ed8"; // Dunkelblau

      case "Wenig": 
        return "#38bdf8"; // Hellblau

      case "Paletten": 
        return "#f59e0b"; // Orange

      case "Topfen": 
        return "#10b981"; // Grün

      default: 
        return "#E0E0E0"; // Grau
    }
  })() 
}}

onClick:
{{
  (() => {
    // 1. Speichern im Hintergrund anstoßen (ohne await / .then)
    Bewaesserung_Update_Status.run({
      "realRowIndex": List_KlimaPC.triggeredItem.rowIndex
    });

    // 2. Daten im Hintergrund neu laden (optional, falls nötig)
    Bewaesserung_Lesen.run();
  })()
}}
